import type React from 'react';

import { Slot } from '@radix-ui/react-slot';

import { cn } from '../utils/cn';
import { linkVariants } from './common/variants';

/**
 * Render a styled link (`<a>`) or component that looks like a link.
 */
function Link({
  asChild,
  className,
  ...props
}: React.ComponentProps<'a'> & {
  asChild?: boolean;
}) {
  const Comp = asChild ? Slot : 'a';

  return (
    <Comp
      data-slot="link"
      className={cn(asChild ? '' : linkVariants(), className)}
      {...props}
    />
  );
}

export { Link };
